sys_script_include.script:
var MagicLinkToken = Class.create();
  MagicLinkToken.prototype = {
      initialize: function() {
          this.secret = gs.getProperty('x_1880990_chain.magic_link_secret');
          this.ttlSeconds = parseInt(gs.getProperty('x_1880990_chain.magic_link_ttl_seconds', '259200'), 10);
      },

      generate: function(proposalSysId, ownerSysId, action) {
          var exp = Math.floor(new Date().getTime() / 1000) + this.ttlSeconds;
          var payload = { p: proposalSysId, o: ownerSysId, a: action, e: exp };
          var payloadJson = JSON.stringify(payload);
          var payloadB64 = this._urlSafe(gs.base64Encode(payloadJson));
          var sig = this._sign(payloadB64);
          return payloadB64 + '.' + sig;
      },    

      verify: function(token) {
          if (!token || token.indexOf('.') === -1) {
              return { valid: false, reason: 'malformed' };
          }
          var parts = token.split('.');
          var payloadB64 = parts[0];
          var sigGiven = parts[1];
          var sigExpected = this._sign(payloadB64);
          if (sigGiven !== sigExpected) {
              return { valid: false, reason: 'invalid_signature' };
          }
          try {
              var payloadJson = gs.base64Decode(this._urlSafeReverse(payloadB64));
              var payload = JSON.parse(payloadJson);
              var now = Math.floor(new Date().getTime() / 1000);
              if (payload.e < now) {
                  return { valid: false, reason: 'expired' };
              }
              return { valid: true, payload: payload };
          } catch (e) {
              return { valid: false, reason: 'parse_error: ' + e.message };
          } 
      },

      _sign: function(payloadB64) {
          var digest = new GlideDigest();
          return digest.getSHA256Hex(this.secret + ':' + payloadB64);
      },

      _urlSafe: function(b64) {
          return b64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
      },

      _urlSafeReverse: function(urlSafe) {
          var b64 = urlSafe.replace(/-/g, '+').replace(/_/g, '/');
          while (b64.length % 4) b64 += '=';
          return b64; 
      },

      type: 'MagicLinkToken'
  };
